import React from 'react';

const Footer = () => {
  return (
    <footer style={{
      background: 'linear-gradient(135deg, #ffffff 0%, #f5f7fa 100%)',
      padding: '1.5rem 0',
      borderTop: '1px solid rgba(0, 0, 0, 0.05)',
      marginTop: 'auto'
    }}>
      <div className="container-fluid">
        <div className="d-flex justify-content-between align-items-center">
          <div className="d-flex align-items-center">
            <img 
              src="/Logo/LSlogo.png" 
              alt="Loyalstring" 
              style={{ 
                height: '25px',
                marginRight: '10px',
                opacity: 0.8
              }} 
            />
            <span style={{
              color: '#666',
              fontSize: '0.9rem',
              fontWeight: 500
            }}>
              © {new Date().getFullYear()} Loyalstring Pvt Ltd. All rights reserved.
            </span>
          </div>
          <div style={{
            color: '#666',
            fontSize: '0.9rem',
            fontWeight: 500
          }}>
            <i className="fas fa-code me-1" style={{ color: '#5470FF' }}></i>
            RFID API Dashboard
          </div>
        </div>
      </div>
    </footer>
  );
};

export default Footer;
